INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES ("vo_minigame_1013_icon_2_003_001", "vo_minigame_1013_icon_1_003_001", 2, 2, "ほらほら、\nまだいけるだろ？", "クスクス、悪くない\n流れですわね", 3000, 2, 5000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES ("vo_minigame_1013_icon_2_004_001", "vo_minigame_1013_icon_1_004_001", 2, 3, "へへっ、おまえら\nやるじゃねえか！", "すばらしい\n記録ですわ", 3000, 3, 10000, 2);
